 1	import type { FC } from 'react';
 2	import { TableIconCell } from 'src/modules/Providers/utils/components/TableCell/TableIconCell';
 3	import { useForkliftTranslation } from 'src/utils/i18n';
 4	
 5	import { Tooltip } from '@patternfly/react-core';
 6	import { OffIcon, PowerOffIcon, UnknownIcon } from '@patternfly/react-icons';
 7	
 8	import { getVmPowerState, type PowerState } from '../utils/helpers/getVmPowerState';
 9	
10	import type { VMCellProps } from './VMCellProps';
11	
12	export const PowerStateCellRenderer: FC<VMCellProps> = ({ data }) => {
13	  const { t } = useForkliftTranslation();
14	  const powerState = getVmPowerState(data?.vm);
15	  const states: Record<PowerState, [JSX.Element, string, string]> = {
16	    off: [<OffIcon color="grey" key="off" />, t('Powered off'), t('Off')],
17	    on: [<PowerOffIcon color="green" key="on" />, t('Powered on'), t('On')],
18	    unknown: [<UnknownIcon key="unknown" />, t('Unknown power state'), t('Unknown')],
19	  };
20	  const [icon, tooltipText, shortText] = states[powerState] || states.unknown;
21	
22	  return (
23	    <TableIconCell icon={<Tooltip content={tooltipText}>{icon}</Tooltip>}>
24	      {shortText}
25	    </TableIconCell>
26	  );
27	};

